  ((SELECT id FROM rpg.phb_feat WHERE slug = 'mobile'), 3, 'Correr em Terreno Difícil', 'Ao executar a ação Correr no seu turno, Terreno Difícil não custa movimento adicional pelo resto deste turno.'),
